import type { UserConfig } from '@hey-api/openapi-ts';
import { defineConfig } from '@hey-api/openapi-ts';
import { defineConfig as openapiParserPlugin } from './src/plugins/openapi-parser/index';
import { defineConfig as tsdocPlugin } from './src/plugins/tsdoc';

/**
 * OpenAPI TS configuration for generating the SDK.
 *
 * The input is a cached OpenAPI JSON generated by the backend.
 *
 * The `output.path` defined here is the final destination.
 * The `generate-sdk.ts` script overrides this to generate to a temp folder first,
 * then compares output and only updates `sdk/gen` on actual changes.
 * This prevents unnecessary file modifications and HMR triggers.
 *
 * @see ../frontend/vite/openapi-watch.ts - Dev server file watcher
 * @see ./src/generate-sdk.ts - Incremental generation wrapper
 */
export const openApiConfig: UserConfig = {
  input: {
    path: '../backend/openapi.cache.json',
    watch: false,
  },
  output: {
    path: './gen',
    source: {
      fileName: 'openapi',
      path: './gen',
    },
  },
  parser: {
    transforms: {
      readWrite: false,
    },
  },
  plugins: [
    tsdocPlugin(),
    openapiParserPlugin(),
    'zod',
    { name: '@hey-api/sdk', responseStyle: 'data', validator: 'zod' },
    {
      name: '@hey-api/client-fetch',
      throwOnError: true,
    },
  ],
};

export default defineConfig(openApiConfig);
